noncompliant:
#include <cstdio>

int main() {
    int i = 0;

    loop:
        printf("i = %d\n", i);
        i++;
        if (i < 10) {
            goto loop;  // Noncompliant: using goto for looping
        }

    return 0;
}

// Another noncompliant example
void processData(int* data, size_t size) {
    for (size_t i = 0; i < size; i++) {
        if (data[i] < 0) {
            goto error_handling;  // Noncompliant: goto for error handling
        }
        // process data[i]
    }
    return;

    error_handling:
        printf("Error: negative value found\n");
}

compliant:
#include <cstdio>

int main() {
    // Compliant: using for loop instead of goto
    for (int i = 0; i < 10; i++) {
        printf("i = %d\n", i);
    }

    return 0;
}

// Another compliant example using structured control flow
void processData(int* data, size_t size) {
    for (size_t i = 0; i < size; i++) {
        if (data[i] < 0) {
            printf("Error: negative value found\n");
            return;  // Compliant: early return instead of goto
        }
        // process data[i]
    }
}
